export const isLastFilledCell = (value, index) => value != null && value.length - 2 === index;
export const getSymbols = (codeValue, codeLength) => {
    const symbols = new Array(codeLength);
    for (let i = 0; i < codeLength; i++) {
        symbols[i] = codeValue[i] ?? '';
    }
    return symbols;
};
